import{_ as e,o as t,a as i,a2 as s}from"./chunks/framework.DCcmcJcL.js";const p=JSON.parse('{"title":"AI in Bagisto","description":"","frontmatter":{},"headers":[],"relativePath":"ai/introduction.md","filePath":"ai/introduction.md","lastUpdated":1782192512000}'),o={name:"ai/introduction.md"};function r(l,a,n,d,c,g){return t(),i("div",null,a[0]||(a[0]=[s('<h1 id="ai-in-bagisto" tabindex="-1">AI in Bagisto <a class="header-anchor" href="#ai-in-bagisto" aria-label="Permalink to &quot;AI in Bagisto&quot;">​</a></h1><p>Bagisto ships with AI built in — both <strong>inside your store</strong> and <strong>inside your development workflow</strong>. This page is the home for everything AI-related: store features powered by AI, and tools that make the AI agents <em>you</em> build with smarter about Bagisto.</p><div class="ai-cards__group-title">For your store</div><div class="ai-cards"><a class="ai-card" href="/ai/magic-ai.html"><div class="ai-card__title">✨ Magic AI</div><div class="ai-card__desc"> Generate product content &amp; images, image search, review translation and personalised checkout messages — powered by your choice of AI provider. </div></a></div><div class="ai-cards__group-title">For developers &amp; AI agents</div><div class="ai-cards"><a class="ai-card" href="/ai/agent-skills.html"><div class="ai-card__title">🧩 Agent Skills</div><div class="ai-card__desc"> Pre-built skills that teach AI coding agents (Claude Code, Cursor, Windsurf) Bagisto&#39;s conventions so they generate correct packages, payment methods and themes. </div></a><a class="ai-card" href="/ai/llms-txt.html"><div class="ai-card__title">📄 llms.txt</div><div class="ai-card__desc"> Context files that help LLMs and AI tools understand Bagisto&#39;s architecture for more accurate, framework-aware suggestions. </div></a></div><h2 id="magic-ai-—-built-into-your-store" tabindex="-1">Magic AI — built into your store <a class="header-anchor" href="#magic-ai-—-built-into-your-store" aria-label="Permalink to &quot;Magic AI — built into your store&quot;">​</a></h2><p><a href="/ai/magic-ai.html">Magic AI</a> is a first-class Bagisto feature. Add an API key for any supported provider and you can:</p><ul><li>✍️ <strong>Generate content</strong> — product descriptions, page copy, and more from the admin editor.</li><li>🖼️ <strong>Generate images</strong> — create product imagery from a text prompt.</li><li>🔍 <strong>Image search</strong> — let shoppers search your catalog by uploading a photo.</li><li>🌐 <strong>Translate reviews</strong> — show customer reviews in the shopper&#39;s language.</li><li>🎉 <strong>Checkout messages</strong> — personalised order confirmation messages.</li></ul><p>Magic AI works with <strong>OpenAI, Anthropic, Gemini, Groq, xAI, DeepSeek, Mistral, and Ollama</strong> — pick a different model per feature, all from the admin panel.</p><h2 id="ai-for-developers" tabindex="-1">AI for developers <a class="header-anchor" href="#ai-for-developers" aria-label="Permalink to &quot;AI for developers&quot;">​</a></h2><p>Bagisto also helps the AI tools <em>you</em> code with:</p><ul><li><strong><a href="/ai/agent-skills.html">Agent Skills</a></strong> — install <code>bagisto/agent-skills</code> so your AI agent generates Bagisto-correct packages, payment methods, themes, and tests.</li><li><strong><a href="/ai/llms-txt.html">llms.txt</a></strong> — point Copilot, Cursor, ChatGPT, or Claude at Bagisto&#39;s context files for architecture-aware answers.</li></ul><div class="tip custom-block"><p class="custom-block-title">Where to start</p><p>Building a store? Start with <strong><a href="/ai/magic-ai.html">Magic AI</a></strong>. Writing code? Install <strong><a href="/ai/agent-skills.html">Agent Skills</a></strong>.</p></div>',14)]))}const m=e(o,[["render",r]]);export{p as __pageData,m as default};
